############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(A.6.6.4) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "niceTables.pl", "contextForm.pl", "parserPopUp.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $actual_solution = Real(random(-9,9) + random(1,9)/10); $m = random(2,9); $b = non_zero_random(-9,9,0.1); $left = Formula("$m x + $b")->reduce; $right = Formula($left->eval(x => $actual_solution))->reduce; $proposed_solution = random(0,1) ? $actual_solution : $actual_solution + non_zero_random(-3,3,0.1); Context("LimitedNumeric"); $lefteval = Real($left->eval(x => $proposed_solution)); $righteval = Real($right->eval(x => $proposed_solution)); $dropdown = DropDown(["Yes, it is a solution.", "No, it is not a solution."], ($lefteval == $righteval) ? 0 : 1, showInStatic => 0);
############################################################ # Body ############################################################
BEGIN_PGML Check if the given number is a solution to the given equation.
Is [`[$proposed_solution]`] a solution to [`[$left]=[$right]\text{?}`]
>> [@DataTable( [ [PGML('[`[$left->TeX]`]'), PGML('[`=`]'), PGML('[`[$right->TeX]`]'), ], [PGML('[_]{$lefteval}{3}'), PGML('[`\wonder{=}`]'), PGML('[`[$righteval->TeX]`]'), ], ], align => 'rcl', valign => 'middle',);@]* <<
[_]{$dropdown}{5}
END_PGML
############################################################ # End Problem ############################################################
